import logging
from dataclasses import dataclass
from typing import Dict, List
import unittest

# Configure logging for production visibility
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

@dataclass
class Item:
    """Represents an inventory item."""
    name: str
    quantity: int

class InventoryError(Exception):
    """Base exception for inventory management errors."""
    pass

class InventoryManager:
    """Manages inventory state with validation and threshold alerts."""

    LOW_STOCK_THRESHOLD = 5

    def __init__(self) -> None:
        self._inventory: Dict[str, Item] = {}

    def _validate_input(self, name: str, quantity: int) -> None:
        """Validates input types and values."""
        if not isinstance(name, str) or not name.strip():
            raise ValueError("Item name must be a non-empty string.")
        if not isinstance(quantity, int):
            raise TypeError("Quantity must be an integer.")

    def add_item(self, name: str, quantity: int) -> None:
        """Adds a new item or increments existing stock."""
        self._validate_input(name, quantity)
        if quantity < 0:
            raise InventoryError("Cannot add negative quantity.")

        if name in self._inventory:
            self._inventory[name].quantity += quantity
        else:
            self._inventory[name] = Item(name, quantity)
        logger.info(f"Added {quantity} to {name}. Total: {self._inventory[name].quantity}")

    def update_stock(self, name: str, quantity: int) -> None:
        """Adjusts existing stock levels."""
        self._validate_input(name, quantity)
        if name not in self._inventory:
            raise KeyError(f"Item '{name}' does not exist in inventory.")

        new_qty = self._inventory[name].quantity + quantity
        if new_qty < 0:
            raise InventoryError("Resulting stock cannot be negative.")

        self._inventory[name].quantity = new_qty

        if self._inventory[name].quantity < self.LOW_STOCK_THRESHOLD:
            logger.warning(f"ALERT: Low stock for {name} ({self._inventory[name].quantity})")

    def get_low_stock_items(self) -> List[Item]:
        """Returns a list of items below the threshold."""
        return [item for item in self._inventory.values() if item.quantity < self.LOW_STOCK_THRESHOLD]

class TestInventoryManager(unittest.TestCase):
    """Unit tests for InventoryManager."""

    def setUp(self) -> None:
        self.manager = InventoryManager()

    def test_add_and_update(self) -> None:
        self.manager.add_item("Apple", 10)
        self.manager.update_stock("Apple", -6)
        self.assertEqual(self.manager._inventory["Apple"].quantity, 4)

    def test_negative_stock_error(self) -> None:
        self.manager.add_item("Banana", 2)
        with self.assertRaises(InventoryError):
            self.manager.update_stock("Banana", -5)

    def test_low_stock_threshold(self) -> None:
        self.manager.add_item("Orange", 10)
        self.manager.update_stock("Orange", -7)
        low_stock = self.manager.get_low_stock_items()
        self.assertEqual(len(low_stock), 1)
        self.assertEqual(low_stock[0].name, "Orange")

    def test_invalid_input(self) -> None:
        with self.assertRaises(ValueError):
            self.manager.add_item("", 10)
        with self.assertRaises(TypeError):
            self.manager.add_item("Pear", "ten") # type: ignore

if __name__ == "__main__":
    unittest.main()
